ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?position ?number_of_branches WHERE {
  ?employees a :Employees .
  ?banks a :Banks .
  ?employees p:hasBanks ?banks .
  ?employees p:Position ?position .
  ?banks p:Number_of_Branches ?number_of_branches .
  ?banks p:Bank ?bank_f .
  FILTER(STR(?bank_f) = "ABC Bank")
} }
  component_2: { SELECT ?position ?countries_served WHERE {
  ?employees a :Employees .
  ?banks a :Banks .
  ?employees p:hasBanks ?banks .
  ?employees p:Position ?position .
  ?banks p:Countries_served ?countries_served .
  ?banks p:Bank ?bank_f .
  FILTER(STR(?bank_f) = "ABC Bank")
} }
  full: { SELECT ?position ?number_of_branches ?countries_served WHERE {
  ?employees a :Employees .
  ?banks a :Banks .
  ?employees p:hasBanks ?banks .
  ?employees p:Position ?position .
  ?banks p:Number_of_Branches ?number_of_branches .
  ?banks p:Countries_served ?countries_served .
  ?banks p:Bank ?bank_f .
  FILTER(STR(?bank_f) = "ABC Bank")
} }
}

